<?php require_once 'db.php'; verify_csrf(); if($_SERVER['REQUEST_METHOD']==='POST'){ $name=trim($_POST['name']??''); $email=filter_var($_POST['email']??'',FILTER_VALIDATE_EMAIL); $pass=$_POST['password']??''; if(!$name||!$email||strlen($pass)<8) flash('Enter valid name, email and password with 8+ characters.','err'); else try{ $rid=pdo()->query("SELECT id FROM roles WHERE name='student'")->fetchColumn(); pdo()->beginTransaction(); $s=pdo()->prepare('INSERT INTO users(role_id,name,email,password,phone) VALUES(?,?,?,?,?)'); $s->execute([$rid,$name,$email,password_hash($pass,PASSWORD_DEFAULT),trim($_POST['phone']??'')]); $uid=pdo()->lastInsertId(); pdo()->prepare('INSERT INTO students(user_id,roll_no,course) VALUES(?,?,?)')->execute([$uid,trim($_POST['roll_no']??''),trim($_POST['course']??'')]); pdo()->commit(); flash('Registration successful. Please login.'); header('Location: login.php'); exit; }catch(Throwable $e){ if(pdo()->inTransaction()) pdo()->rollBack(); flash('Registration failed: duplicate email or database error.','err'); }} app_header('Register'); ?><form class="auth card" method="post"><h1>Student Registration</h1><?=csrf_field()?><input name="name" placeholder="Full name" required><input name="email" type="email" placeholder="Email" required><input name="phone" placeholder="Phone"><input name="roll_no" placeholder="Roll number"><input name="course" placeholder="Course"><input name="password" type="password" minlength="8" placeholder="Password" required><button class="btn">Create account</button></form><?php app_footer(); ?>
